mapper.select:
SELECT i.id, i.store_id, s.store_name, i.product_id, p.product_name, p.product_code, i.quantity, i.expiry_date, i.received_at, i.status, i.lot_number, i.location, i.last_count_date, i.remarks, i.create_time, i.update_time FROM retail_inventory i LEFT JOIN retail_store s ON i.store_id = s.id LEFT JOIN retail_product p ON i.product_id = p.id
i.is_deleted = 0
AND i.store_id = #{query.storeId}
AND p.product_name LIKE CONCAT('%', #{query.productName}, '%')
AND i.status = #{query.status}
AND i.lot_number LIKE CONCAT('%', #{query.lotNumber}, '%')
AND i.expiry_date >= #{query.expiryDateStart}
AND i.expiry_date <= #{query.expiryDateEnd}
ORDER BY i.update_time DESC
